//-------------------------------------------------------------------------
// 적수계산
//-------------------------------------------------------------------------
scwin.f_MonthProcess = async function() {

    let ret = await $c.gus.cfValidate([ica_closeYm]);
    if (!ret) {
        return false;
    }

    var sMonth = ica_closeYm.getValue().trim();
    let confirmResult = await $c.win.confirm(sMonth.substring(0,4)+"년"+sMonth.substring(4,6)+"월"+" 적수를 생성하시겠습니까?");
    if (confirmResult) {
        $c.sbm.execute(sbm_fundSettlementOfAccounts);
    }

};

scwin.sbm_fundSettlementOfAccounts_submitdone = async function (e) {
    await $c.win.alert("성공적으로 처리되었습니다.");
};
